  1	import * as React from 'react';
  2	import { Alert, Button, ButtonVariant } from '@patternfly/react-core';
  3	import { kialiStyle } from 'styles/StyleUtils';
  4	import { isKioskMode } from '../utils/SearchParamUtils';
  5	
  6	import { PF_THEME_DARK, Theme } from 'types/Common';
  7	import { getKialiTheme } from 'utils/ThemeUtils';
  8	import { kialiLogoDark, kialiLogoLight } from 'config';
  9	
 10	type initializingScreenProps = {
 11	  errorMsg?: string;
 12	  errorDetails?: string;
 13	};
 14	
 15	const defaultErrorStyle = kialiStyle({
 16	  $nest: {
 17	    '& > textarea': {
 18	      display: 'none'
 19	    },
 20	    '& > p:last-of-type': {
 21	      marginTop: '3em'
 22	    }
 23	  }
 24	});
 25	
 26	const expandedErrorStyle = kialiStyle({
 27	  $nest: {
 28	    '& > p:last-of-type': {
 29	      display: 'none'
 30	    },
 31	    '& > textarea': {
 32	      width: '100%',
 33	      whiteSpace: 'pre',
 34	      marginTop: '3em'
 35	    }
 36	  }
 37	});
 38	
 39	const centerVerticalHorizontalStyle = kialiStyle({
 40	  position: 'relative',
 41	  top: '10em',
 42	  textAlign: 'center',
 43	  $nest: {
 44	    '& > img': {
 45	      marginBottom: '3em'
 46	    },
 47	    '& > div': {
 48	      width: '40em',
 49	      marginLeft: 'auto',
 50	      marginRight: 'auto',
 51	      textAlign: 'left'
 52	    }
 53	  }
 54	});
 55	
 56	export const InitializingScreen: React.FC<initializingScreenProps> = (props: initializingScreenProps) => {
 57	  const errorDiv = React.createRef<HTMLDivElement>();
 58	
 59	  if (isKioskMode()) {
 60	    document.body.classList.add('kiosk');
 61	  }
 62	
 63	  const theme = getKialiTheme();
 64	  if (theme === Theme.DARK) {
 65	    document.documentElement.classList.add(PF_THEME_DARK);
 66	  }
 67	
 68	  return (
 69	    <div data-test="loading-screen" className={centerVerticalHorizontalStyle}>
 70	      <img alt="Kiali Logo" src={theme === Theme.DARK ? kialiLogoDark : kialiLogoLight} width="200" />
 71	      {props.errorMsg ? (
 72	        <div ref={errorDiv} className={defaultErrorStyle}>
 73	          <Alert variant="danger" isInline={true} title={props.errorMsg} />
 74	          {props.errorDetails ? (
 75	            <>
 76	              <p>
 77	                <Button
 78	                  variant={ButtonVariant.link}
 79	                  onClick={e => {
 80	                    e.preventDefault();
 81	                    if (errorDiv.current) {
 82	                      errorDiv.current.setAttribute('class', expandedErrorStyle);
 83	                    }
 84	                  }}
 85	                >
 86	                  Show details
 87	                </Button>
 88	              </p>
 89	              <textarea readOnly={true} rows={10}>
 90	                {props.errorDetails}
 91	              </textarea>
 92	            </>
 93	          ) : null}
 94	        </div>
 95	      ) : (
 96	        <h1>Loading...</h1>
 97	      )}
 98	    </div>
 99	  );
100	};

